<style scoped lang="scss">
.sp-filter-form {
  margin-bottom: 16px;
}
</style>

<template>
  <div>
    <template v-if="$route.path.indexOf('editor') === -1">
<!--      <SpPlatformTip h5 app pc alipay />-->
      <div class="action-container">
        <el-button type="primary" icon="iconfont icon-xinzengcaozuo-01" @click="addActivityData">
          新增活動
        </el-button>
      </div>

      <SpFilterForm :model="params" @onSearch="onSearch" @onReset="onReset">
        <SpFilterFormItem prop="marketing_name" label="活動名稱:">
          <el-input v-model="params.marketing_name" placeholder="活動名稱" />
        </SpFilterFormItem>
        <SpFilterFormItem prop="status" label="活動狀態:">
          <el-select v-model="params.status" placeholder="活動狀態" clearable style="width: 100%">
            <el-option label="全部" value="0" />
            <el-option label="待開始" value="waiting" />
            <el-option label="進行中" value="ongoing" />
            <el-option label="已結束" value="end" />
          </el-select>
        </SpFilterFormItem>
        <SpFilterFormItem prop="create_time" label="時間:">
          <el-date-picker
            v-model="params.create_time"
            type="daterange"
            value-format="yyyy/MM/dd"
            placeholder="新增時間篩選"
            style="width: 100%; min-width: 250px"
          />
        </SpFilterFormItem>
      </SpFilterForm>

      <el-table v-loading="loading" border :data="tableList" :height="wheight - 150">
        <el-table-column prop="marketing_id" label="ID" width="50" />
        <el-table-column prop="marketing_name" label="團購名稱" />
        <el-table-column label="活動時間" width="190">
          <template slot-scope="scope">
            {{ scope.row.start_date }} <span class="text-muted">開始</span>
            {{ scope.row.end_date }} <span class="text-muted">結束</span>
          </template>
        </el-table-column>
        <el-table-column label="商品有效期" width="190">
          <template slot-scope="scope">
            {{ scope.row.commodity_effective_start_date }} <span v-if="scope.row.commodity_effective_start_date" class="text-muted">開始</span>
            {{ scope.row.commodity_effective_end_date }} <span v-if="scope.row.commodity_effective_end_date" class="text-muted">結束</span>
          </template>
        </el-table-column>
        <el-table-column label="商品訊息" align="center" min-width="420">
          <template slot-scope="scope">
            <div style="display: flex;flex-direction: column;align-items: center;">
              <div
                v-for="(s_item, s_key) in scope.row.condition_list"
                :key="s_key"
                style="display: flex;"
              >
                <div style="width: 220px;display: flex; align-items: center; padding-right: 10px;justify-content: center;">
                  {{ s_item.item_name }} {{ s_item.item_spec_desc }}
                </div>
                <div>
                  <div v-for="(item, key) in s_item.condition_value" :key="key">
                    購買
                    {{ item.min }}
                    ~
                    {{ item.max }}
                    件，單件
                    {{ item.act_price }}
                    台幣
                  </div>
                </div>
              </div>
            </div>
          </template>
        </el-table-column>
        <el-table-column prop="status" label="狀態" width="70">
          <template slot-scope="scope">
            <span v-if="scope.row.status == 'waiting'">待開始</span>
            <span v-else-if="scope.row.status == 'ongoing'">進行中</span>
            <span v-else-if="scope.row.status == 'end'">已結束</span>
          </template>
        </el-table-column>
        <el-table-column label="操作" width="150">
          <template slot-scope="scope">
            <div class="operating-icons">
              <el-button
                v-if="scope.row.status == 'waiting' || scope.row.status == 'ongoing'"
                type="text"
                @click="editCommunityAction(scope.$index, scope.row)"
              >
                編輯
              </el-button>
              <el-button
                v-if="scope.row.status == 'ongoing'"
                type="text"
                @click="updateStatusCommunityAction(scope.row)"
              >
                終止
              </el-button>
              <el-button
                v-if="scope.row.status == 'waiting'"
                type="text"
                @click="deleteCommunityAction(scope.row)"
              >
                刪除
              </el-button>
            </div>
          </template>
        </el-table-column>
      </el-table>
      <div v-if="page.total > page.pageSize" class="content-center content-top-padded">
        <el-pagination
          background
          layout="total, sizes, prev, pager, next, jumper"
          :current-page.sync="page.pageIndex"
          :page-sizes="[10, 20, 50]"
          :total="page.total"
          :page-size="page.pageSize"
          @current-change="onCurrentChange"
          @size-change="onSizeChange"
        />
      </div>
    </template>
    <router-view />
  </div>
</template>
<script>
import { mapGetters } from 'vuex'

import mixin, { pageMixin } from '@/mixins'

export default {
  mixins: [mixin, pageMixin],
  props: ['getStatus'],
  provide() {
    return {
      refresh: this.refresh
    }
  },
  data() {
    const initialParams = {
      marketing_name: undefined,
      status: undefined,
      create_time: [],
      commodity_effective: [],
    }
    return {
      initialParams,
      params: {
        ...initialParams
      },
      tableList: [],
      loading: false
    }
  },
  computed: {
    ...mapGetters(['wheight'])
  },
  watch: {
    getStatus(val) {
      if (val) {
        this.getActivityLists(this.params)
      }
    }
  },
  mounted() {
    if (this.$route.query.status) {
      this.params.status = this.$route.query.status
    }
    this.fetchList()
  },
  methods: {
    onSearch() {
      this.page.pageIndex = 1
      this.$nextTick(() => {
        this.fetchList()
      })
    },
    onReset() {
      this.params = { ...this.initialParams }
      this.onSearch()
    },
    addActivityData() {
      this.$router.push({ path: this.matchHidePage('editor') })
    },
    editCommunityAction(index, row) {
      this.$router.push({ path: this.matchHidePage('editor/') + row.marketing_id })
    },
    getParams() {
      const time = {}
      const create_time = this.params.create_time
      if (create_time && create_time.length > 0) {
        time.start_time = this.dateStrToTimeStamp(create_time[0] + ' 00:00:00')
        time.end_time = this.dateStrToTimeStamp(create_time[1] + ' 23:59:59')
      }
      const commodity_effective = this.params.commodity_effective
      if (commodity_effective && commodity_effective.length > 0) {
        time.commodity_effective_start_time = this.dateStrToTimeStamp(commodity_effective[0] + ' 00:00:00')
        time.commodity_effective_end_time = this.dateStrToTimeStamp(commodity_effective[1] + ' 23:59:59')
      }
      let params = {
        ...this.params,
        status: this.params.status === 'all' ? undefined : this.params.status,
        create_time: [],
        commodity_effective: [],
        ...time
      }
      return params
    },
    async fetchList() {
      this.loading = true
      const { pageIndex: page, pageSize } = this.page
      let params = {
        page,
        pageSize,
        marketing_type: 'multi_buy',
        ...this.getParams()
      }
      const { list, total_count } = await this.$api.promotions.multibuyGetList(params)
      this.tableList = list
      this.page.total = total_count
      this.loading = false
    },
    dateStrToTimeStamp(str) {
      return Date.parse(new Date(str)) / 1000
    },
    refresh() {
      this.fetchList(this.params)
    },
    updateStatusCommunityAction(row) {
      var msg = '此操作將終止該活動, 是否繼續?'
      this.$confirm(msg, '提示', {
        cancelButtonText: '取消',
        confirmButtonText: '確定',
        type: 'warning',
        beforeClose: (action, instance, done) => {
          if (action === 'confirm') {
            this.$api.promotions
              .removeMultibuyActivity({ marketing_id: row.marketing_id, isEnd: true })
              .then((response) => {
                this.fetchList()
                this.$message({
                  message: '修改活動狀態成功',
                  type: 'success',
                  duration: 5 * 1000
                })
              })
          }
          done()
        }
      })
    },
    deleteCommunityAction(row) {
      var msg = '此操作將刪除該活動, 是否繼續?'
      this.$confirm(msg, '提示', {
        cancelButtonText: '取消',
        confirmButtonText: '確定',
        type: 'warning',
        beforeClose: (action, instance, done) => {
          if (action === 'confirm') {
            this.$api.promotions
              .removeMultibuyActivity({ marketing_id: row.marketing_id, isEnd: false })
              .then((response) => {
                this.fetchList()
                this.$message({
                  message: '刪除活動成功',
                  type: 'success',
                  duration: 5 * 1000
                })
              })
          }
          done()
        }
      })
    }
  }
}
</script>
